components.css:
.ds-masthead {
  border-bottom: 3px double var(--color-rule);
  padding: 24px 6vw 18px;
  background: var(--color-paper);
  position: relative;
}
.ds-masthead-top {
  display: flex;
  justify-content: space-between;
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-muted);
  border-bottom: 1px solid var(--color-rule);
  padding-bottom: 10px;
  margin-bottom: 18px;
}
.ds-masthead-title {
  font-family: var(--font-display);
  font-weight: var(--weight-display);
  font-size: var(--size-display);
  line-height: var(--leading-display);
  letter-spacing: var(--tracking-display);
  text-align: center;
  font-variation-settings: "opsz" 144;
  margin: 0;
}
.ds-masthead-title em {
  font-style: italic;
  font-weight: 500;
  color: var(--color-ember);
}
.ds-masthead-sub {
  text-align: center;
  margin-top: 14px;
  font-style: italic;
  font-size: var(--size-subtitle);
  color: var(--color-muted);
  font-weight: 400;
  font-family: var(--font-body);
}
.ds-masthead-meta {
  display: flex;
  justify-content: center;
  gap: 32px;
  margin-top: 18px;
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}
.ds-masthead-meta span::before {
  content: "\00a7 ";
  color: var(--color-ember-text);
}

.ds-toc {
  background: var(--color-paper);
  border: 1px solid var(--color-rule);
  padding: 24px 28px;
  margin: 32px 0 48px;
  columns: 2;
  column-gap: 36px;
}
@media (max-width: 700px) {
  .ds-toc { columns: 1; }
}
.ds-toc-title {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  margin-bottom: 14px;
  color: var(--color-ember-text);
  column-span: all;
  border-bottom: 1px solid var(--color-rule);
  padding-bottom: 8px;
}
.ds-toc ol {
  list-style: none;
  counter-reset: toc;
  padding: 0;
  margin: 0;
}
.ds-toc li {
  counter-increment: toc;
  padding: 6px 0;
  font-size: var(--size-small);
  break-inside: avoid;
}
.ds-toc li::before {
  content: counter(toc, upper-roman) ".";
  font-family: var(--font-label);
  color: var(--color-ember-text);
  margin-right: 10px;
  font-size: var(--size-label);
}
.ds-toc a {
  color: var(--color-ink);
  text-decoration: none;
  border-bottom: 1px solid transparent;
  transition: border-color 0.18s;
  font-style: italic;
}
.ds-toc a:hover { border-color: var(--color-ember); }
.ds-toc a:focus-visible { outline: 2px solid var(--color-ember); outline-offset: 2px; }

.ds-chapter-mark {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  color: var(--color-ember-text);
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
  font-weight: var(--weight-label);
}
.ds-chapter-mark::after {
  content: "";
  flex: 1;
  height: 1px;
  background: var(--color-rule);
  opacity: 0.3;
}

.ds-headline {
  font-family: var(--font-display);
  font-weight: var(--weight-headline);
  font-size: var(--size-headline);
  line-height: var(--leading-headline);
  letter-spacing: var(--tracking-headline);
  margin: 0 0 24px;
  font-variation-settings: "opsz" 144;
  color: var(--color-ink);
}
.ds-headline em {
  font-style: italic;
  color: var(--color-ember);
}
.ds-title-heading {
  font-family: var(--font-display);
  font-weight: var(--weight-title);
  font-size: var(--size-title);
  margin: 36px 0 12px;
  letter-spacing: var(--tracking-title);
  color: var(--color-ink);
}

.ds-lede {
  font-family: var(--font-body);
  font-size: var(--size-lede);
  font-style: italic;
  color: var(--color-muted);
  margin: 0 0 28px;
  max-width: 60ch;
  line-height: var(--leading-lede);
}

.ds-dropcap {
  font-family: var(--font-body);
  font-size: var(--size-body);
  line-height: var(--leading-body);
  max-width: var(--measure);
  margin: 0 0 16px;
  color: var(--color-ink);
}
.ds-dropcap::first-letter {
  font-family: var(--font-display);
  font-weight: 500;
  font-size: 5em;
  float: left;
  line-height: 0.85;
  margin: 6px 10px -4px 0;
  color: var(--color-ember);
  font-style: italic;
}

.ds-ornament {
  text-align: center;
  color: var(--color-ember);
  font-size: var(--size-title-lg);
  margin: 50px 0;
  letter-spacing: 0.5em;
}

.ds-def {
  background: var(--color-paper);
  border: 1px solid var(--color-rule);
  padding: 28px 32px;
  margin: 24px 0;
  position: relative;
  border-radius: 0;
}
.ds-def-tag {
  position: absolute;
  top: -11px;
  left: 24px;
  padding: 3px 14px;
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  font-weight: var(--weight-label);
}
.ds-def-tag-default {
  background: var(--color-ink);
  color: var(--color-paper);
}
.ds-def-tag-moss {
  background: var(--color-moss);
  color: var(--color-paper);
}
.ds-def-title {
  font-family: var(--font-display);
  font-style: italic;
  font-size: var(--size-title-lg);
  margin-bottom: 10px;
  font-weight: 500;
}
.ds-def-default .ds-def-title { color: var(--color-ember); }
.ds-def-moss .ds-def-title { color: var(--color-moss); }
.ds-def-body {
  font-family: var(--font-body);
  font-size: var(--size-body);
  line-height: var(--leading-body);
  color: var(--color-ink);
}
.ds-def-body p { max-width: none; margin: 0 0 10px; }
.ds-hl-prime { color: var(--color-ember-text); font-weight: 700; }
@media (max-width: 600px) {
  .ds-def { padding: 20px 16px; }
  .ds-def-tag { left: 16px; }
}

.ds-thm {
  background: var(--color-ink);
  color: var(--color-paper);
  padding: 32px 36px;
  margin: 32px 0;
  position: relative;
  border-radius: var(--radius-sm);
}
.ds-thm-tag {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: 0.3em;
  color: var(--color-gilt);
  margin-bottom: 6px;
  font-weight: var(--weight-label);
  text-transform: uppercase;
}
.ds-thm-title {
  font-family: var(--font-display);
  font-size: var(--size-title-lg);
  font-style: italic;
  margin-bottom: 14px;
  font-weight: 500;
}
.ds-thm-body {
  font-family: var(--font-body);
  font-size: var(--size-body);
  line-height: 1.6;
}
.ds-thm-body p { max-width: none; margin: 0 0 8px; }
.ds-thm-body ol {
  padding-left: var(--space-lg);
  margin-top: var(--space-sm);
  list-style: decimal;
}
.ds-thm-body ol li { margin-bottom: var(--space-sm); }
@media (max-width: 600px) {
  .ds-thm { padding: 24px 18px; }
}

.ds-prop {
  background: var(--color-paper);
  border: 1px solid var(--color-rule);
  padding: 24px 28px;
  margin: 28px 0;
  position: relative;
}
.ds-prop-tag {
  position: absolute;
  top: -10px;
  left: 22px;
  padding: 2px 12px;
  background: var(--color-paper);
  color: var(--color-ember-text);
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  font-weight: var(--weight-label);
}
.ds-prop-title {
  font-family: var(--font-display);
  font-style: italic;
  font-size: var(--size-title);
  margin-bottom: 10px;
  font-weight: 500;
  color: var(--color-ink);
}
.ds-prop-body {
  font-family: var(--font-body);
  font-size: var(--size-body);
  line-height: 1.6;
  color: var(--color-ink);
}
.ds-prop-body p { max-width: none; margin: 0 0 10px; }
@media (max-width: 600px) {
  .ds-prop { padding: 18px 16px; }
  .ds-prop-tag { left: 14px; }
}

.ds-lemma {
  border-top: 1px solid var(--color-rule);
  border-bottom: 1px solid var(--color-rule);
  padding: 16px 0;
  margin: 24px 0;
  background: transparent;
}
.ds-lemma-head {
  display: flex;
  align-items: baseline;
  gap: 14px;
  margin-bottom: 8px;
}
.ds-lemma-tag {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  font-weight: var(--weight-label);
  color: var(--color-muted);
  flex-shrink: 0;
}
.ds-lemma-title {
  font-family: var(--font-display);
  font-style: italic;
  font-size: var(--size-title-sm);
  font-weight: 500;
  color: var(--color-ink);
  line-height: 1.25;
}
.ds-lemma-body {
  font-family: var(--font-body);
  font-size: var(--size-small);
  line-height: 1.6;
  color: var(--color-ink);
}
.ds-lemma-body p { max-width: none; margin: 0 0 8px; }
.ds-lemma-body p:last-child { margin: 0; }

.ds-corollary {
  border-left: 1px solid var(--color-moss);
  padding: 4px 0 4px 14px;
  margin: 14px 0 14px 8px;
  font-family: var(--font-body);
  font-size: var(--size-body);
  line-height: 1.55;
}
.ds-corollary-tag {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  font-weight: var(--weight-label);
  color: var(--color-moss);
  margin-right: 10px;
}
.ds-corollary-body { color: var(--color-ink); }
.ds-corollary-body p { display: inline; max-width: none; margin: 0; }

.ds-intuition {
  background: linear-gradient(135deg, oklch(90% 0.035 85), oklch(96% 0.015 27));
  border-left: 4px solid var(--color-gilt);
  padding: 22px 28px;
  margin: 24px 0;
  font-family: var(--font-body);
  font-style: italic;
  font-size: var(--size-body);
  line-height: var(--leading-body);
  color: var(--color-ink);
}
.ds-intuition p { max-width: none; margin: 0 0 8px; }
.ds-intuition p:last-child { margin: 0; }
.ds-intuition-tag {
  font-family: var(--font-label);
  font-style: normal;
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  color: var(--color-gilt-text);
  margin-bottom: 8px;
  font-weight: var(--weight-label);
  text-transform: uppercase;
}
@media (max-width: 600px) {
  .ds-intuition { padding: 16px 14px; }
}

.ds-sketch {
  border: 1px dashed var(--color-muted);
  padding: 18px 24px;
  margin: 16px 0;
  font-family: var(--font-body);
  font-size: var(--size-small);
  line-height: 1.65;
  color: var(--color-ink);
  background: oklch(99% 0.002 80 / 0.4);
}
.ds-sketch-tag {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  color: var(--color-muted);
  margin-bottom: 6px;
  font-weight: var(--weight-label);
  text-transform: uppercase;
}
.ds-sketch p { max-width: none; margin: 0 0 8px; }
.ds-sketch p:last-child { margin: 0; }

.ds-example {
  background: oklch(94% 0.02 155);
  border-left: 4px solid var(--color-moss);
  padding: 20px 26px;
  margin: 20px 0;
  font-family: var(--font-body);
  font-size: var(--size-body);
  line-height: var(--leading-body);
  color: var(--color-ink);
}
.ds-example p { max-width: none; margin: 0 0 8px; }
.ds-example p:last-child { margin: 0; }
.ds-example-tag {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  color: var(--color-moss);
  margin-bottom: 6px;
  font-weight: var(--weight-label);
  text-transform: uppercase;
}

.ds-app {
  background: var(--color-paper);
  border: 1px solid var(--color-rule);
  border-left: 3px solid var(--color-moss);
  padding: 24px 28px;
  margin: 20px 0;
  position: relative;
  font-family: var(--font-body);
  color: var(--color-ink);
}
.ds-app-num {
  position: absolute;
  top: -16px;
  left: 18px;
  background: var(--color-moss);
  color: var(--color-paper);
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-display);
  font-style: italic;
  font-weight: 500;
  font-size: var(--size-subtitle);
  border-radius: 50%;
}
.ds-app-title {
  font-family: var(--font-display);
  font-style: italic;
  font-size: var(--size-title-sm);
  margin: 0 0 10px 26px;
  font-weight: 500;
}
.ds-app p { max-width: none; margin: 0 0 8px; }
.ds-app p:last-child { margin: 0; }
@media (max-width: 600px) {
  .ds-app { padding: 20px 16px; }
}

.ds-panel {
  background: var(--color-paper);
  border: 1px solid var(--color-rule);
  padding: 28px;
  margin: 32px 0;
  border-radius: var(--radius-sm);
  transition: box-shadow 180ms cubic-bezier(0.22, 0.68, 0.35, 1.0);
}
.ds-panel:hover, .ds-panel:focus-within {
  box-shadow: 3px 3px 0 rgba(26,22,18,0.06);
}
.ds-panel-header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  border-bottom: 1px dashed var(--color-rule);
  padding-bottom: 12px;
  margin-bottom: 20px;
}
.ds-panel-title {
  font-family: var(--font-display);
  font-style: italic;
  font-size: var(--size-title-lg);
  color: var(--color-ink);
  font-weight: 500;
}
.ds-panel-tag {
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: var(--tracking-label);
  text-transform: uppercase;
  color: var(--color-muted);
  font-weight: var(--weight-label);
}
.ds-num-picker {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin: 16px 0 20px;
}
.ds-num-btn {
  font-family: var(--font-mono);
  font-size: var(--size-mono);
  font-weight: var(--weight-mono);
  padding: 8px 14px;
  background: var(--color-parchment);
  color: var(--color-ink);
  border: 1px solid var(--color-rule);
  cursor: pointer;
  transition: all 180ms cubic-bezier(0.22, 0.68, 0.35, 1.0);
  border-radius: 0;
}
.ds-num-btn:hover {
  background: var(--color-soft);
  transform: translateY(-1px);
}
.ds-num-btn-active, .ds-num-btn:active {
  background: var(--color-ink);
  color: var(--color-paper);
  transform: translateY(-1px);
  box-shadow: 2px 2px 0 var(--color-ember);
}
.ds-num-btn:focus-visible {
  outline: 2px solid var(--color-ember);
  outline-offset: 2px;
}
@media (max-width: 600px) {
  .ds-panel { padding: 18px 14px; }
}

.ds-math-display {
  margin: 12px 0;
  text-align: center;
  overflow-x: auto;
  overflow-y: hidden;
  padding: var(--space-xs) 0;
}
.ds-math-display .katex {
  font-size: var(--size-math) !important;
}
.ds-math-display .katex-display {
  margin: 0 !important;
}

.ds-hl-prime { color: var(--color-ember-text); font-weight: 700; }
.ds-hl-moss  { color: var(--color-moss); font-weight: 700; }
.ds-hl-slate { color: var(--color-slate-blue); font-weight: 700; }
.ds-hl-gilt  { color: var(--color-gilt); font-weight: 700; }
.ds-hl-ink   { color: var(--color-ink); font-weight: 700; }

.ds-two-col {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
  margin: 24px 0;
}
@media (max-width: 720px) {
  .ds-two-col { grid-template-columns: 1fr; }
}

.ds-footer {
  border-top: 3px double var(--color-rule);
  margin-top: 60px;
  padding: 30px 6vw;
  text-align: center;
  font-family: var(--font-label);
  font-size: var(--size-label);
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--color-muted);
  background: var(--color-paper);
  font-weight: var(--weight-label);
}
.ds-footer-accent { color: var(--color-ember); }
